import { ApiError, apiRequest } from '@reeve/shared';
// ─── Manufacturers ─────────────────────────────────────────────────────────
export function getManufacturers(isDomestic) {
    return apiRequest('/admin/manufacturers', {
        query: { is_domestic: isDomestic, limit: 1000 },
    });
}
export function createManufacturer(data) {
    return apiRequest('/admin/manufacturers', { method: 'POST', body: data });
}
// ─── Vehicle Models ────────────────────────────────────────────────────────
export function getVehicleModels(manufacturerId) {
    return apiRequest('/admin/vehicle-models', {
        query: { manufacturer_id: manufacturerId, limit: 1000 },
    });
}
export function createVehicleModel(data) {
    return apiRequest('/admin/vehicle-models', { method: 'POST', body: data });
}
export function getAnalyzedVehicles(args = {}) {
    return apiRequest('/admin/analyzed-vehicles', {
        query: {
            skip: args.skip,
            limit: args.limit,
            status: args.status === 'all' ? undefined : args.status,
            manufacturer_id: args.manufacturer_id,
            model_id: args.model_id,
        },
    });
}
export function getVehicleCounts() {
    return apiRequest('/admin/analyzed-vehicles-counts');
}
export function deleteAnalyzedVehicle(id) {
    return apiRequest(`/admin/review/${id}`, { method: 'DELETE' });
}
export function deleteAllUnverified() {
    return apiRequest('/admin/review-delete-all', { method: 'DELETE' });
}
export function updateAnalyzedVehicle(id, body) {
    return apiRequest(`/admin/review/${id}`, {
        method: 'PATCH',
        body,
    });
}
export function saveToTraining(id) {
    return apiRequest(`/admin/review/${id}`, {
        method: 'POST',
    });
}
export function reanalyzeVehicle(id) {
    return apiRequest(`/admin/analyze/${id}`, {
        method: 'POST',
    });
}
// ─── Finetune ──────────────────────────────────────────────────────────────
export function getFinetuneMode() {
    return apiRequest('/finetune/mode');
}
export function getFinetuneStats() {
    return apiRequest('/finetune/stats');
}
export function getHwProfile() {
    return apiRequest('/finetune/hw-profile');
}
export function getFreezeEpochsInfo() {
    return apiRequest('/finetune/freeze-epochs');
}
export function exportEfficientNet(args = {}) {
    return apiRequest('/finetune/export-efficientnet', {
        method: 'POST',
        body: { split: 0.9, ...args },
    });
}
export function startTraining(config) {
    return apiRequest('/finetune/train/start', { method: 'POST', body: config });
}
export function stopTraining() {
    return apiRequest('/finetune/train/stop', { method: 'POST' });
}
export function getTrainStatus() {
    return apiRequest('/finetune/train/status');
}
export function getTrainLogs(tail = 100) {
    return apiRequest('/finetune/train/logs', { query: { tail } });
}
export function getRawLog(tail = 100) {
    return apiRequest('/finetune/train/raw-log', { query: { tail } });
}
export function evaluateModel(sampleSize = 50) {
    return apiRequest('/finetune/evaluate', { query: { sample_size: sampleSize } });
}
// ─── Error helper ──────────────────────────────────────────────────────────
export function extractErrorMessage(err) {
    if (err instanceof ApiError) {
        const body = err.body;
        if (body && typeof body === 'object' && 'detail' in body) {
            const { detail } = body;
            if (typeof detail === 'string' && detail.trim())
                return detail;
        }
        if (typeof body === 'string' && body.trim())
            return body;
        return `HTTP ${err.status}`;
    }
    if (err instanceof Error)
        return err.message;
    return String(err);
}
