import { apiRequest } from '@reeve/shared';
export async function uploadFile(file, source, clientUuid) {
    const form = new FormData();
    form.append('file', file);
    form.append('source', source);
    form.append('client_uuid', clientUuid);
    return apiRequest('/api/upload', { method: 'POST', body: form });
}
export async function detectVehicle(analyzedId) {
    const form = new FormData();
    form.append('analyzed_id', String(analyzedId));
    return apiRequest('/api/detect-vehicle', { method: 'POST', body: form });
}
export async function* streamAnalyze(analyzedId, bbox) {
    const form = new FormData();
    form.append('analyzed_id', String(analyzedId));
    form.append('bbox', JSON.stringify(bbox));
    const res = await fetch('/api/analyze-vehicle-stream', { method: 'POST', body: form });
    if (!res.ok || !res.body) {
        let detail = `HTTP ${res.status}`;
        try {
            const body = (await res.json());
            if (body?.detail)
                detail = body.detail;
        }
        catch {
            /* ignore */
        }
        throw new Error(detail);
    }
    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buffer = '';
    while (true) {
        const { done, value } = await reader.read();
        if (done)
            break;
        buffer += decoder.decode(value, { stream: true });
        let idx;
        while ((idx = buffer.indexOf('\n\n')) !== -1) {
            const chunk = buffer.slice(0, idx);
            buffer = buffer.slice(idx + 2);
            for (const line of chunk.split('\n')) {
                if (!line.startsWith('data:'))
                    continue;
                const payload = line.slice(5).trim();
                if (!payload)
                    continue;
                try {
                    yield JSON.parse(payload);
                }
                catch {
                    /* ignore malformed chunk */
                }
            }
        }
    }
}
